public static string Underscore(this string input)
{
    if (string.IsNullOrEmpty(input))
    {
        return input;
    }

    // Single-pass StringBuilder instead of triple regex Replace chain
    var sb = new StringBuilder(input.Length + 4);
    for (var i = 0; i < input.Length; i++)
    {
        var c = input[i];

        if (c == '-' || c == ' ')
        {
            sb.Append('_');
            continue;
        }

        if (char.IsUpper(c))
        {
            if (i > 0)
            {
                var prev = input[i - 1];
                var hasNext = i + 1 < input.Length;

                // Insert underscore between lowercase/digit and uppercase: "aB" → "a_B"
                if (char.IsLower(prev) || char.IsDigit(prev))
                {
                    sb.Append('_');
                }
                // Insert underscore in uppercase runs before a final lowercase: "ABc" → "A_Bc"
                else if (char.IsUpper(prev) && hasNext && char.IsLower(input[i + 1]))
                {
                    sb.Append('_');
                }
            }

            sb.Append(char.ToLowerInvariant(c));
        }
        else
        {
            sb.Append(c);
        }
    }

    return sb.ToString();
}

